import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PollenType {
  name: string;
  level: number;
  category: string;
}

interface PollenTrend {
  day: string;
  level: number;
}

interface PollenData {
  location: string;
  currentPollenLevel: {
    level: number;
    category: string;
    types: PollenType[];
  };
  pollenTrend: PollenTrend[];
}

export default function Widget() {
  const pollenData = response.data as PollenData;
  const { location, currentPollenLevel, pollenTrend } = pollenData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFF8E1' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h6" fontWeight={700} sx={{ color: '#FF5722' }}>
              Current Pollen Level: {currentPollenLevel.level} ({currentPollenLevel.category})
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {currentPollenLevel.types.map((type) => (
                <Chip
                  key={type.name}
                  label={`${type.name}: ${type.level} (${type.category})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFE0B2' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              series={[
                {
                  data: pollenTrend.map((trend) => trend.level),
                  color: '#4CAF50',
                },
              ]}
              xAxis={[
                {
                  data: pollenTrend.map((trend) => trend.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
